#define NULL ((void *)0)

/* *
 * Rounding operations (efficient when n is a power of 2)
 * Round down to the nearest multiple of n
 * */
#define ROUNDDOWN(a, n)                                                                                                \
    ({                                                                                                                 \
        size_t __a = (size_t)(a);                                                                                      \
        (typeof(a))(__a - __a % (n));                                                                                  \
    })

/* Round up to the nearest multiple of n */
#define ROUNDUP(a, n)                                                                                                  \
    ({                                                                                                                 \
        size_t __n = (size_t)(n);                                                                                      \
        (typeof(a))(ROUNDDOWN((size_t)(a) + __n - 1, __n));                                                            \
    })

/* Return the offset of 'member' relative to the beginning of a struct type */
#define offset_of(type, member) ((size_t)(&((type *)0)->member))

/* *
 * container_of - cast a member of a structure out to the containing structure
 * @ptr:    the pointer to the member.
 * @type:   the type of the container struct this is embedded in.
 * @member: the name of the member within the struct.
 * */
#define container_of(ptr, type, member)                                                                                \
    ({                                                                                                                 \
        const typeof(((type *)0)->member) *__mptr = (ptr);                                                             \
        (type *)((char *)__mptr - offset_of(type, member));                                                            \
    })

/* *
 * range_of - get the range of a struct
 * @type:   the type of the struct
 * @start:  the start member of the struct
 * @end:    the end member of the struct
 * */
#define range_of(type, start, end) (offset_of(type, end) - offset_of(type, start))

/* *
 * to_struct - get the struct from a ptr
 * @ptr:    a struct pointer of member
 * @type:   the type of the struct this is embedded in
 * @member: the name of the member within the struct
 * */
#define to_struct(ptr, type, member) ((type *)((char *)(ptr)-offset_of(type, member)))

#define MIN(_a, _b)                                                                                                    \
    ({                                                                                                                 \
        typeof(_a) __a = (_a);                                                                                         \
        typeof(_b) __b = (_b);                                                                                         \
        __a <= __b ? __a : __b;                                                                                        \
    })

#define MAX(_a, _b)                                                                                                    \
    ({                                                                                                                 \
        typeof(_a) __a = (_a);                                                                                         \
        typeof(_b) __b = (_b);                                                                                         \
        __a >= __b ? __a : __b;                                                                                        \
    })

#endif /* __TYPES_H__ */

